    StateGraph = class {
      constructor() {
        this.nodes = /* @__PURE__ */ new Map();
        this.edges = /* @__PURE__ */ new Map();
        this.entryPoint = "";
      }
      addNode(name, func) {
        this.nodes.set(name, func);
        return this;
      }
      setEntryPoint(name) {
        this.entryPoint = name;
        return this;
      }
      addConditionalEdges(source, condition, mapping) {
        this.edges.set(source, (state) => mapping[condition(state)] || mapping["default"]);
        return this;
      }
      addEdge(source, target) {
        this.edges.set(source, { default: target });
        return this;
      }
      async compileAndRun(initialState) {
        let currentState = { ...initialState };
        let currentNode = this.entryPoint;
        const MAX_ITERATIONS = 20;
        let iterations = 0;
        while (currentNode && currentNode !== "END") {
          if (++iterations > MAX_ITERATIONS) {
            logger.error(`[StateGraph] Max iterations (${MAX_ITERATIONS}) exceeded. Forcing END.`);
            currentState.finalResponse = currentState.t("ai.msg_system_busy");
            currentState.isSysMsg = true;
            break;
          }
          const nodeFunc = this.nodes.get(currentNode);
          if (!nodeFunc) throw new Error(`Node ${currentNode} not found`);
          try {
            const updates3 = await nodeFunc(currentState);
            currentState = { ...currentState, ...updates3 };
            const edge = this.edges.get(currentNode);
            if (typeof edge === "function") {
              currentNode = edge(currentState);
            } else if (edge && edge.default) {
              currentNode = edge.default;
            } else {
              currentNode = "END";
            }
          } catch (error48) {
            logger.error(`Error in node ${currentNode}:`, error48);
            currentState.trace.push({ id: `err_${Date.now()}`, node: "ERROR", status: "ERROR", output: error48.message, timestamp: Date.now() });
            currentState.finalResponse = currentState.t("ai.msg_system_busy");
            currentState.isSysMsg = true;
            currentState.error = error48;
            break;
          }
        }
        return currentState;
      }
    };
