        const responseBonus = avgMins == null ? 0 : avgMins <= 10 ? 30 : avgMins <= 30 ? 20 : avgMins <= 60 ? 10 : 0;
        const slaScore = Math.min(100, Math.round(row.close_rate * 0.7 + responseBonus));
