// server/routes/tenantRoutes.ts
init_db();
import { Router as Router23 } from "express";
var DEFAULT_CONFIG = {
  primaryColor: "#4F46E5",
  features: { enableZalo: true, maxUsers: 100 }
};
function createTenantRoutes(authenticateToken) {
  const router = Router23();
  router.get("/", authenticateToken, async (req, res) => {
    try {
      const user = req.user;
      const tenantId = user?.tenantId;
      if (!tenantId) {
        return res.status(400).json({ error: "No tenant context" });
      }
      const result = await pool.query(
        `SELECT id, name, domain, config FROM tenants WHERE id = $1`,
        [tenantId]
      );
      if (result.rows.length === 0) {
        return res.status(404).json({ error: "Tenant not found" });
      }
      const row = result.rows[0];
      const config2 = row.config && Object.keys(row.config).length > 0 ? row.config : DEFAULT_CONFIG;
      res.json({
        id: row.id,
        name: row.name,
        domain: row.domain,
        config: config2
      });
    } catch (error48) {
      console.error("Error fetching tenant:", error48);
      res.status(500).json({ error: "Failed to fetch tenant" });
    }
  });
  return router;
}

